SELECT d.dormitory_id, d.name, d.region, d.postal_code, d.address, d.layout_type, d.gender_type, d.nearest_station_1, d.nearest_station_2, d.nearest_station_3, d.remarks, d.created_at, d.updated_at, d.deleted_at, EXISTS ( SELECT 1 FROM residence_history rh WHERE rh.dormitory_id = d.dormitory_id AND rh.deleted_at IS NULL AND rh.move_in_date <= CURRENT_DATE AND (rh.move_out_date IS NULL OR rh.move_out_date >= CURRENT_DATE) ) AS has_residents FROM dormitory d WHERE d.deleted_at IS NULL
AND d.dormitory_id = #{dormitoryId}
AND d.name ILIKE CONCAT('%', #{name}, '%')
AND d.gender_type = #{genderType}
AND d.region = #{region}
AND d.address ILIKE CONCAT('%', #{address}, '%')
ORDER BY has_residents DESC, d.updated_at DESC, d.region ASC NULLS LAST, d.name ASC, d.dormitory_id ASC
ORDER BY d.dormitory_id
LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(1)
FROM dormitory
WHERE deleted_at IS NULL

    AND dormitory_id = #{dormitoryId}


    AND name ILIKE CONCAT('%', #{name}, '%')


    AND gender_type = #{genderType}


    AND region = #{region}


    AND address ILIKE CONCAT('%', #{address}, '%')

SELECT 
FROM dormitory
WHERE deleted_at IS NULL

    AND region IN

        #{region}



    AND dormitory_id = #{dormitoryId}


    AND gender_type = #{genderType}

ORDER BY name
